class QueryComplexityValidator:
    def __init__(self, max_depth=5, max_complexity=100, timeout_seconds=5):
        self.max_depth = max_depth
        self.max_complexity = max_complexity
        self.timeout_seconds = timeout_seconds
        self.query_cache = {}
        self.rate_limit_store = defaultdict(list)
        
    def calculate_complexity(self, info) -> int:
        complexity = 0
        depth = 0
        
        def traverse(node, current_depth=0):
            nonlocal complexity, depth
            depth = max(depth, current_depth)
            
            if hasattr(node, 'selections'):
                for selection in node.selections:
                    complexity += 1
                    if hasattr(selection, 'selection_set') and selection.selection_set:
                        traverse(selection.selection_set, current_depth + 1)
        
        if hasattr(info, 'field_nodes'):
            for field_node in info.field_nodes:
                if hasattr(field_node, 'selection_set') and field_node.selection_set:
                    traverse(field_node.selection_set)
        
        return complexity, depth
    
    def get_query_hash(self, query_string: str) -> str:
        return hashlib.sha256(query_string.encode()).hexdigest()
    
    def check_rate_limit(self, client_id: str, max_requests=100, window_seconds=60) -> bool:
        current_time = time.time()
        requests = self.rate_limit_store[client_id]
        requests = [req_time for req_time in requests if current_time - req_time < window_seconds]
        
        if len(requests) >= max_requests:
            return False
        
        requests.append(current_time)
        self.rate_limit_store[client_id] = requests
        return True
    
    def validate(self, info, client_id: str = "default"):
        if not self.check_rate_limit(client_id):
            raise Exception("Rate limit exceeded")
        
        complexity, depth = self.calculate_complexity(info)
        
        if depth > self.max_depth:
            raise Exception(f"Query depth {depth} exceeds maximum allowed depth {self.max_depth}")
        
        if complexity > self.max_complexity:
            raise Exception(f"Query complexity {complexity} exceeds maximum allowed complexity {self.max_complexity}")

